window.SmartRisk=window.SmartRisk||{};SmartRisk.Modal={open({title,body,confirmLabel="Aceptar",onConfirm=null}){const r=document.getElementById("app-modal-root"),close=()=>{r.innerHTML="";document.body.classList.remove("is-locked")};r.innerHTML=`<div class="modal-backdrop"><section class="modal" role="dialog" aria-modal="true"><header class="modal-header"><h2 class="section-title">${title}</h2><button id="modal-close" class="icon-btn">×</button></header><div class="modal-body">${body}</div><footer class="modal-footer"><button id="modal-cancel" class="btn btn-secondary">Cerrar</button><button id="modal-confirm" class="btn btn-primary">${confirmLabel}</button></footer></section></div>`;document.body.classList.add("is-locked");document.getElementById("modal-close").onclick=close;document.getElementById("modal-cancel").onclick=close;document.getElementById("modal-confirm").onclick=()=>{onConfirm?.();close()}}};